courses = [
  {"code":"HU201","title":"Humanities - English","department":"English","level":200,"honors":False,"interdisciplinary":False,"terms":["T1","T2","T3"],"forms":["II"],"year_long":True,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Yearlong English class stressing development of writing, grammar, close reading, and discussion skills. Introduces works in the literary canon. Begins with intensive writing focusing on students' place at Lawrenceville. Uses modern and ancient stories to spur thinking. Builds foundation of skills and knowledge for the beginning student of the humanities.","tags":["writing","grammar","close reading","discussion","literary canon","yearlong"]},
  {"code":"EN301","title":"English III","department":"English","level":300,"honors":False,"interdisciplinary":False,"terms":["T1","T2","T3"],"forms":["III"],"year_long":True,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Year-long English class developing reading, writing, discussion, and analysis skills through short fiction, poetry, and drama. Reads Baldwin, Dickinson, Fitzgerald, Hansberry, Hughes, Kahf, O'Connor, and Shakespeare's Macbeth. Writing assignments ask students to read closely and derive and support an argument.","tags":["fiction","poetry","drama","Shakespeare","Macbeth","analysis","yearlong"]},
  {"code":"EN421","title":"The Novel","department":"English","level":400,"honors":False,"interdisciplinary":False,"terms":["T2"],"forms":["IV"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Devoted to the study of long-form fiction. Reading materials include novels by diverse authors from the nineteenth and twentieth centuries. Analytical writing plays a central role with students composing papers on each of three novels. Discussion-based inquiry around the Harkness table.","tags":["novel","long-form fiction","analytical writing","Harkness","19th century","20th century"]},
  {"code":"EN422","title":"Advanced Poetry","department":"English","level":400,"honors":False,"interdisciplinary":False,"terms":["T1"],"forms":["IV"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"IV Formers apply close reading and literary analysis skills to poetry. First five weeks devoted to analysis of poems by diverse authors. Second five weeks feature intensive study of Shakespeare's Hamlet. Includes poetry recitation, dramatic recitation, and student-led discussion.","tags":["poetry","close reading","Shakespeare","Hamlet","recitation","analysis"]},
  {"code":"EN423","title":"Essay Writing","department":"English","level":400,"honors":False,"interdisciplinary":False,"terms":["T3"],"forms":["IV"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Students read three or four exemplary essays per week from The Norton Reader and other sources, becoming familiar with rhetorical techniques. Students write a short essay approximately every week-and-a-half. Second half emphasizes revision. Final assignment is a capstone essay expanded, condensed, and revised over several weeks.","tags":["essay","nonfiction","rhetoric","revision","Norton Reader","capstone"]},
  {"code":"EN501","title":"Writing Seminar","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Structured practice building receptive and expressive literacy skills for transitioning into other 500-level English electives. Students collaborate to develop strong habits and processes for drafting and revising. Reads short stories, a novel, and poems. For returning students wanting to develop specific literacy skills and new V Form or post-graduate students.","tags":["writing","literacy","drafting","revision","seminar","500-level"]},
  {"code":"EN502","title":"Writing Seminar II","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Extension of Writing Seminar I, continuing to build students' ability to identify key evidence and draw significant conclusions about texts. Engages students in readings based on areas of interest and prior knowledge, supporting development of individual voice and style. Students who took EN501 may continue, or students from other fall electives may enroll.","tags":["writing","analytical writing","seminar","voice","style","500-level"]},
  {"code":"EN506","title":"Literary Journalism","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Literary Journalists adhere to ethics and methods of journalism but create rich non-fiction stories with hard-hitting facts and emotional weight. Reads John McPhee, Norman Simms, Adrian LeBlanc. Students craft their own vignettes and create a newsworthy article. Students may submit for publication.","tags":["journalism","nonfiction","McPhee","vignettes","publication","reporting"]},
  {"code":"EN507","title":"Literature of National Pastime","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Baseball has captivated the literary imagination in a manner unique in American sporting landscape. Reads Malamud's The Natural, DeLillo's Pafko at the Wall, Lewis' Moneyball. Shorter readings explore the Negro Leagues, baseball in Japan and Latin America, women in baseball, and mythical 20th century figures.","tags":["baseball","American literature","Malamud","DeLillo","Moneyball","sports"]},
  {"code":"EN508","title":"African American Literature","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Focuses on American writers after the Harlem Renaissance, emphasizing fiction and poetry. Central concern is the effort of Black writers to explore the conflicting claims of their identities as both African and American. Reads Wright, Ellison (Invisible Man), Morrison (Song of Solomon), Baldwin, Hayden, Rita Dove, and Kendrick Lamar.","tags":["African American","Harlem Renaissance","Morrison","Baldwin","hip-hop","Ellison"]},
  {"code":"EN509","title":"Advanced Literary Research","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":["Participation in Merrill Scholars Summer Program"],"ncaa_grants":[],"description":"Merrill Scholar program: a literary research experience for rising V formers with keen interest and ability in literature. Students expand summer research into an individual senior thesis while being introduced to the conventions and discipline of literary scholarship.","tags":["research","thesis","Merrill Scholars","literary scholarship","senior thesis"]},
  {"code":"EN510","title":"Literature of the Beat Generation: On the Road to Rebellion","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Examines the Beats and their literary and social influence on American culture. Focuses on the birth and height of the Beat movement in the 1940s and 50s, and the Beats' impact on literature, music, and social issues of the 1960s and 70s including anti-war, civil rights, gay rights, and women's movements.","tags":["Beat Generation","Kerouac","Ginsberg","counterculture","1950s","rebellion"]},
  {"code":"EN511","title":"Creative Writing: Techniques in Poetry and Short Fiction","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2","T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Three elements: reading and discussing very contemporary (last 5-10 years) poetry and short stories; writing original short stories and poetry; workshopping creative writing in class. Students leave with a small collection of their own creative writing.","tags":["creative writing","poetry","short fiction","workshop","contemporary","portfolio"]},
  {"code":"EN512","title":"Radical Love in African American Literature: Nonfiction and Poetry","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Students read works by queer Black authors beginning with bell hooks' All About Love, then Audre Lorde, Saeed Jones, Danez Smith, and Alice Walker. Discusses queer and heteroromantic love, familial love, love between friends, and developing a 'love ethic.' Students leave with a portfolio of poetry, memoir chapters, podcast episode, or documentary.","tags":["African American","queer","bell hooks","Audre Lorde","love","social change","nonfiction"]},
  {"code":"EN514","title":"Award-Winning 21st-Century American Fiction","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Uses award-winning contemporary literature to dive deep into issues of racialized marginalization. Texts include Jesmyn Ward's Sing Unburied Sing (National Book Award), Colson Whitehead's The Underground Railroad and The Nickel Boys (Pulitzer/NBA), and Laila Lalami's The Other Americans.","tags":["contemporary fiction","National Book Award","Pulitzer","race","marginalization","21st century"]},
  {"code":"EN515","title":"Radical Love in African American Literature","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Builds on bell hooks' All About Love, Baldwin's A Fire Next Time, and Lorde's Sister Outsider. Focuses on connections between ancestry and social justice. Reads Lorde's Zami, Coates' Between the World and Me, Julie Dash's Daughters of the Dust, Beyonce's Lemonade. Final project: podcast, mini-documentary, series of poetry, or memoir chapters.","tags":["African American","social justice","Baldwin","Coates","Beyonce","Lemonade","ancestry"]},
  {"code":"EN516","title":"Essays of Reflection","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Helps students transform key moments in their lives into instructive experience through writing one essay per week. Students recollect significant events — family rituals, Outward Bound, Humanities classes — and communicate who they've been, who they are, and where they might be going. One essay per week plus a final essay.","tags":["memoir","personal essay","reflection","revision","identity","weekly writing"]},
  {"code":"EN517","title":"Doing Philosophy with the Movies: Other Minds, Acting, Being and Perception","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Learns to 'read' films through philosophical lenses, pairing philosophical readings with films. Driven by questions about acting, lying, pretending, truth-telling, authenticity, consciousness, and ethics. Reads Anscombe, Austin, Wittgenstein, Cavell. Watches and writes about Hitchcock films.","tags":["philosophy","film","Hitchcock","Wittgenstein","consciousness","authenticity","ethics"]},
  {"code":"EN518","title":"Literature as Philosophy","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Investigates ways philosophers have used literature to present new ideas and how writers have mixed philosophy into fiction. Reads Plato's Five Dialogues, Jean-Dominique Bauby's The Diving Bell and the Butterfly, and Ted Chiang's Exhalation. Students write a major paper on each main work.","tags":["philosophy","literature","Plato","Ted Chiang","value","knowledge","Bauby"]},
  {"code":"EN519","title":"The Antichrist: Re-Imagining the Devil as a Foundational Hero","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Examines the Devil as one of fiction's greatest villains. Through the Devil's understanding of human nature, his mission to corrupt it, and his unlikely compassion for the human condition, this course critically examines three classic texts invoking this character and producing substantial conversations about morality and theology.","tags":["devil","villain","morality","theology","Paradise Lost","mythology"]},
  {"code":"EN520","title":"From Freud to the Void","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Grounds in Freud's psychoanalytic theory (The Rat Man, Civilization and its Discontents), then traces it through post-war American repression (Cheever, Salinger), the Beat Generation (Kerouac, Ginsberg, Burroughs), into the 60s-80s, and ends with Hunter S. Thompson. Three essays and a final paper.","tags":["Freud","psychoanalysis","Beat Generation","Kerouac","Thompson","1950s","American literature"]},
  {"code":"EN522","title":"Inventing Truth: The Art of Memoir","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Explores the memoir as a form, highlighting successful 21st-century memoirists navigating themes of cultural, racial, and sexual identity. First half: read and analyze critically. Second half: craft own personal narratives. Assessed on daily preparation and active participation in class discussions.","tags":["memoir","identity","race","creative nonfiction","storytelling","21st century"]},
  {"code":"EN523","title":"Hemingway","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Reads The Nick Adams Stories, A Farewell to Arms, The Sun Also Rises, and For Whom the Bell Tolls. Because Hemingway the man is as fascinating as Hemingway the writer, also reads selected biography excerpts. Writing assignments include the opportunity to write in the style of Hemingway.","tags":["Hemingway","modernism","biography","style imitation","war literature","A Farewell to Arms"]},
  {"code":"EN526","title":"Flash Fiction","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Explores the art of the short short story (less than 750 words) from reading and writing perspectives. Students read a wide variety of flash fiction pieces, then use these as models for creating their own. Includes weekly workshop component, deep dives into identifying narrative strategies, and a final portfolio.","tags":["flash fiction","short story","workshop","portfolio","narrative","750 words"]},
  {"code":"EN528","title":"Law as Literature","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Looks at law as literature in two ways: literature focusing on legal issues (executions, battles to change the law, failures of rule of law), and legal texts (statutes, judicial opinions, Constitution) read as literary texts. Planned interviews with prosecutors, public defenders, and judges. Students spend a day witnessing a trial.","tags":["law","literature","Camus","Capote","judicial opinion","trial","legal system"]},
  {"code":"EN530","title":"Remembrance in Literature: Legacy, Archival, and the Self","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Students examine works related to memory, time, and space to inquire how each contributes to the composition of the self. Analytical essay writing at beginning and end; opportunities for poetry and short stories in the middle. Texts may include Ocean Vuong's Time is a Mother, Everything Everywhere All at Once, and Virginia Woolf's The Waves.","tags":["memory","identity","Ocean Vuong","Virginia Woolf","archive","self","multimodal"]},
  {"code":"EN531","title":"Chekhov","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"After brief study of Ibsen's The Wild Duck, reads Chekhov's four major plays: The Seagull, Uncle Vanya, Three Sisters, and The Cherry Orchard. Chekhov's life as a physician and his short fiction inform the study. Three comparative essays and a collaborative final assignment allowing students to perform and analyze a favorite scene.","tags":["Chekhov","drama","Russian literature","Ibsen","theatre","comparative analysis"]},
  {"code":"EN532","title":"Practicum in Poetic Forms","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Takes students through classic categories of poetic form: Haiku, Tanka, Cinquain, Sonnet, Limerick, Villanelle, Paradelle, Sestina, Ghazal, Blues lyric, Sea Shanty, Double Dactyl, Ballad, and Blank Verse. Students study characteristics, read exemplary work, then compose and present poems within each form. Thorough review of meter, rhyme, and poetic devices.","tags":["poetry","poetic forms","sonnet","villanelle","sestina","ghazal","meter","rhyme"]},
  {"code":"EN533","title":"Moby Dick","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Intensive reading of Herman Melville's Moby Dick (1851). Examines Melville's analogues and sources, and the historical and cultural issues informing the novel. Students keep a log or journal of their reactions as the Pequod sails round the world. Two short essays and a longer final paper. May include Bartleby the Scrivener and Billy Budd.","tags":["Melville","Moby Dick","American novel","whaling","19th century","masterpiece"]},
  {"code":"EN534","title":"Sociology as Literature: Theories of Society as Literary Texts","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Re-appreciates foundational sociological texts as works of literature. Narrows gaps in students' knowledge of key sociological paradigms while re-appreciating these works as literature. Charts a pathway from the Father of Sociology to contemporary sociologist Neil Postman. Examines texts giving birth to 'Marxist,' 'Communist,' and 'Capitalist' coinages.","tags":["sociology","Marx","capitalism","Postman","theory","literary analysis"]},
  {"code":"EN535","title":"The Multigenre Writing Workshop","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Workshop emphasizing student writing across short stories, poems, and essays. Arranged thematically, model texts provide direct examples of successful writing. Students write in two genres each week (a poem and either a short story or essay). Half of class time devoted to workshopping peer writing. Growth mindset required.","tags":["writing workshop","multigenre","poetry","fiction","essay","peer review","workshop"]},
  {"code":"EN536","title":"Creative Non-Fiction","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Students grapple with where to draw the line between fiction and non-fiction, whether memory is a fair primary source, and how distinct that line actually is. Reads Zadie Smith, John Jeremiah Sullivan, David Sedaris, Aimee Nezhukumatathil, Robin Wall Kimmerer. Students produce fact-based essays, memoirs, and researched-based creative nonfiction.","tags":["creative nonfiction","memoir","Sedaris","Zadie Smith","hybrid genre","nonfiction"]},
  {"code":"EN537","title":"From Dithyramb to Dr. Dre: Life through Lyricism","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Students explore social, emotional, and political landscapes through song lyrics and lyricism from ancient Greek dithyrambs to contemporary genres. Examines how each era's music traditions construct a living history of lyricism and its influence on identity formation. Texts include The Theory of the Lyric, The Hip Hop Wars, and Blackbird Singing.","tags":["lyricism","hip-hop","music","ancient Greece","identity","cultural history","Tricia Rose"]},
  {"code":"EN538","title":"Science Fiction: Imagined Futures","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Addresses complex questions around unknown futures, foreign prophecies, advanced technologies. Reads Ted Chiang's Stories of Your Life and Others, Ursula K. Le Guin's The Unreal and the Real, plus work by Octavia Butler and Philip K. Dick. Cinematic works include Arrival (2016), Dune (2021), The Twilight Zone, and Night Gallery.","tags":["science fiction","Ted Chiang","Le Guin","Octavia Butler","Dune","Twilight Zone","speculative"]},
  {"code":"EN541","title":"Poetry of the Now: Contemporary American Poetry Seminar","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Half writing original poetry, half reading and discussing contemporary poetry. Focus on the current golden age of poetry built by today's poets of historically marginalized communities (LGBTQ+ poets, BIPOC poets). Class reads a book by the Merrill Visiting Poet before spending time learning directly from them. Final project: collection of original poems plus analytical component.","tags":["contemporary poetry","LGBTQ+","BIPOC","creative writing","visiting poet","Merrill"]},
  {"code":"EN543","title":"Opinions and Events","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1","T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Examines The New York Times, The Wall Street Journal, The New Yorker, and The Atlantic, as well as various other print and social media outlets. Students learn media literacy skills including reading laterally, fact-checking, and identifying bias. Students synthesize findings into bi-weekly opinion pieces.","tags":["media literacy","current events","opinion writing","journalism","fact-checking","NYT","WSJ"]},
  {"code":"EN544","title":"Shakespeare's Comedies: Masks We Wear","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Closely examines three comedies (Twelfth Night, The Merchant of Venice, Much Ado About Nothing) focusing on disguise and deceit. Each raises questions about the morality of hiding one's true identity. Video versions supplement the texts. Time at the start of term dedicated to college application personal essays.","tags":["Shakespeare","comedy","disguise","identity","Twelfth Night","Merchant of Venice","Much Ado"]},
  {"code":"EN547","title":"The Screwball Comedy: From Shakespeare to Hollywood and Beyond","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Examines screwball comedy starting with Shakespeare's Much Ado About Nothing, then Classic Hollywood (1930s-40s), then Jeffrey Eugenides' The Marriage Plot. Uses informative criticism of the genre. Framing questions: what defines the genre, what social concerns these stories reveal, why comedy often wavers close to tragedy.","tags":["comedy","Shakespeare","Hollywood","Eugenides","Marriage Plot","romantic comedy","genre"]},
  {"code":"EN548","title":"West of Everything","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Studies the West of the American Imagination in the 20th century through Western novels, film, and television. Includes Cormac McCarthy's All the Pretty Horses and Blood Meridian, Michael Ondaatje's The Collected Works of Billy the Kid, films from John Ford's Stagecoach to Eastwood's Unforgiven and Cooper's Hostiles. Students forewarned of graphic frontier violence.","tags":["Western","American myth","McCarthy","John Ford","frontier","violence","Ondaatje"]},
  {"code":"EN549","title":"Linguistics: Dr. Johnson to Dr. Chomsky","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Students investigate the astonishing properties of language: lexicography, theories of the origins of language, syntax and semantics, etymology, phonetic transcription, universal grammar, slang and dialect, neurolinguistics, and artificial intelligence. Begins with Samuel Johnson's 1755 Dictionary. Reads de Saussure, Peirce, Chomsky, Searle, Edelman, Bickerton, Pinker.","tags":["linguistics","Chomsky","grammar","etymology","neurolinguistics","AI","Johnson"]},
  {"code":"EN552","title":"Children's Literature","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Explores why early stories and memories shape who we become, revisiting and reanalyzing picture books through first chapter books. Balances nostalgia (Dr. Seuss) with critical examination of racism in childhood favorites. Students analyze existing stories and create their own. Work with faculty children on campus.","tags":["children's literature","Dr. Seuss","picture books","race","nostalgia","critical analysis"]},
  {"code":"EN554","title":"The Art of Biblical Narrative","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Introduction to the Bible as literature using Robert Alter's new translation of the Hebrew Bible and the Revised Standard Version. Focuses on the first five books attributed to Moses, plus Psalms, Job, Isaiah, and the Gospel of Matthew. Expressly designed for students with little or no experience reading the Bible.","tags":["Bible","Hebrew Bible","narrative","Robert Alter","Genesis","literature","Psalms"]},
  {"code":"EN556","title":"Modern English Plays","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Examines changes in British theatre in the 20th century. Reads at least six plays including Wilde's The Importance of Being Earnest and An Ideal Husband, J.B. Priestley's An Inspector Calls and Time and the Conways, and Stoppard's Rosencrantz and Guildenstern are Dead and The Real Inspector Hound.","tags":["British drama","Wilde","Stoppard","Priestley","absurdism","20th century","comedy"]},
  {"code":"EN558","title":"Fairy Tales: Happy Endings or Grimm","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Explores what a fairy tale is and why we love stories full of dreams but also heartbreak and bloodshed, using literary critique and theory. Students examine characters like the Little Mermaid as boundary-breaking adventure seekers or passive damsels. Asks what a 21st century fairy tale looks like.","tags":["fairy tales","Grimm","literary theory","gender","folklore","Disney","Little Mermaid"]},
  {"code":"EN559","title":"The Graphic Novel Project","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Students explore how text and image work together in graphic novels, develop a vocabulary of graphic novel terms, and co-create a single graphic novel to be published as a class using the Stanford Graphic Novel Project approach. Possible texts include Watchmen, V for Vendetta, Persepolis, March, Black Panther: A Nation Under Our Feet.","tags":["graphic novel","comics","Watchmen","Persepolis","March","visual storytelling","publication"]},
  {"code":"EN561","title":"Heart of Darkness in Fact, Fiction, and Film","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Examines King Leopold II's imperial conquest of the Congo and America's involvement in Vietnam through Hochschild's King Leopold's Ghost, Conrad's Heart of Darkness, Logevall's Origins of the Vietnam War, and Coppola's Apocalypse Now. Explores the ruthless hypocrisy of imperialism and the nature of modernist storytelling.","tags":["Conrad","Heart of Darkness","imperialism","Vietnam","Apocalypse Now","colonialism"]},
  {"code":"EN563","title":"American Literature and the Free Market","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Looks at the way literature offers a human view of the American marketplace. From Dreiser's Sister Carrie (a how-to-succeed story) to Saul Bellow's tale of a man who loses everything in stocks, examines how the American free-market economy shapes the lives of literary characters.","tags":["capitalism","American literature","Dreiser","Bellow","economics","class","free market"]},
  {"code":"EN565","title":"War Stories","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Recent course texts include Pat Barker's Regeneration (Booker Prize finalist, WWI shell shock), Kevin Powers's The Yellow Birds (National Book Award finalist, Iraq War), and Phil Klay's Redeployment (National Book Award, stories of combat and its repercussions for young veterans returning home).","tags":["war","WWI","Iraq War","trauma","veterans","National Book Award","Klay"]},
  {"code":"EN567","title":"Reading and Writing with Octavia Butler","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Reads many works by Octavia Butler including Parable of the Sower, Patternmaster, and 'Bloodchild.' Supplemented by adrienne maree brown, Anais Duplan, and Sun Ra. Explores Afro-futurism, time travel, slavery, biotechnology, ecology, dystopia, and liberation. Students write two short stories conjuring a world akin to Butler's.","tags":["Octavia Butler","Afrofuturism","science fiction","dystopia","liberation","creative writing"]},
  {"code":"EN574","title":"One Term, One Text: Reading the Greats","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"The class spends the term reading one great novel in depth alongside the author's biography and the novel's historical context. The novel for Spring 2026 is Charles Dickens' Great Expectations. Supplementary texts may include Shyam Selvadurai's Funny Boy, Virginia Woolf's Mrs. Dalloway on Bond Street, and poetry by Ocean Vuong.","tags":["Dickens","Great Expectations","Victorian","close reading","single text","biography"]},
  {"code":"EN575","title":"The Campus Novel: Examining Our Institutions in Comedies and Farces","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"description":"Charts a course through campus novels that capture the beauty of educational havens and their most trenchant squabbles, giving students a chance to critically examine themselves in the institutions within which they are enmeshed. Invokes Baldwin's paradox of education: as one becomes conscious one begins to examine the society in which one is being educated.","tags":["campus novel","academia","satire","institutions","comedy","identity","Baldwin"]},
  {"code":"EN578","title":"Dystopian Literature and Social Protest","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Examines fictional and historical accounts of seemingly progressive societies that repress narratives of internal social oppression. Texts may include Sir Thomas More's Utopia, Margaret Atwood's The Handmaid's Tale, and Claudia Rankine's Citizen. Assignments include reader responses, analytical essays, and a final project.","tags":["dystopia","Atwood","Handmaid's Tale","social protest","Utopia","Rankine","Citizen"]},
  {"code":"EN581","title":"American Voices: Literary Movements (1865-Present)","department":"English","level":500,"honors":True,"interdisciplinary":False,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"description":"Survey of American Literature from the aftermath of the Civil War through present day, covering significant works and authors from Realism to Modernism and Contemporary era literature. Includes a wide variety of racial, ethnic, and gendered perspectives. Builds literary vocabulary through hands-on engaging assignments.","tags":["American literature","survey","Realism","Modernism","contemporary","1865","literary movements"]},
  # Interdisciplinary - English housed
  {"code":"IN502","title":"American Indian Literatures: Sovereign Nations, Authentic Narratives","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"credits":"1IN/1EN","description":"Focuses on issues fundamental to American Indian literature: major themes, relevance of tribal histories and cultural background, and the importance of sovereignty. Focus on fiction and poetry by modern and contemporary American Indian writers from various tribes of North America. Pays close attention to themes of place, community, and self-governance.","tags":["American Indian","sovereignty","Indigenous literature","tribal history","authenticity","place"]},
  {"code":"IN503","title":"Chaucer: Text and Context","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"credits":"1IN/1EN","description":"Exploring Geoffrey Chaucer and the culture of the late medieval world. Uses Barbara Tuchman's A Distant Mirror to understand the contradictions of the 'calamitous 14th Century.' Canterbury Tales depicts individuals struggling against self-contradictory social forces. Reads in Middle English; no previous experience required.","tags":["Chaucer","Canterbury Tales","Middle English","medieval","gender","class","Tuchman"]},
  {"code":"IN504","title":"Legal Practice and Procedures","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":["EN401"],"ncaa_grants":["SS"],"credits":"1IN/1EN","description":"Main conduit to the Lawrenceville Mock Trial Team. Educates students on the principles of the American legal system during actual litigation. Covers civil vs. criminal litigation, rules of direct vs. cross-examination, and rules of evidence including hearsay exceptions. Students read case details closely, write openings, closings, and witness statements.","tags":["mock trial","law","litigation","evidence","courtroom","legal system","cross-examination"]},
  {"code":"IN505","title":"Writings in International Strategy","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"credits":"1IN/1EN","description":"Students read historic and contemporary texts regarding the origins, evolution, and execution of strategy. Foundation for analysis of Great Power politics and irregular conflicts. Studies the use of strategy in war and coercion. Students use the analysis model and targeting model to identify states' and non-state actors' interests, behaviors, and strategies.","tags":["strategy","international relations","Great Power","military","policy","non-state actors"]},
  {"code":"IN506","title":"Case Studies in International Strategy","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T2","T3"],"forms":["V"],"year_long":False,"prerequisites":["IN505"],"ncaa_grants":["ENG"],"credits":"2IN/2EN","description":"Students work on real problems facing the U.S. Department of Defense. Studies structures and processes of national security agencies. Course culminates with student presentations to teachers, Batten School professionals, and DoD stakeholders in Washington, DC or virtually.","tags":["national security","DoD","strategy","case study","policy","Washington DC","presentations"]},
  {"code":"IN509","title":"Moral of the Story: Ethics through Literature","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"credits":"1IN/1EN","description":"Students establish basic understanding of key ethical theories and critically evaluate their implications in literature. Reads short stories, novels, plays, and philosophical essays. Works may include Kazuo Ishiguro, Aldous Huxley, Octavia Butler, Alison Bechdel, and Arthur Miller. Students write both analytical and creative essays synthesizing literature and ethical theory.","tags":["ethics","literature","Ishiguro","Huxley","moral philosophy","dilemma","synthesis"]},
  {"code":"IN512","title":"Heuristics","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":["ENG"],"credits":"1IN/1EN","description":"Each week organized around a heuristic concept: Freud's unconscious, Heisenberg's Uncertainty Principle, Chomsky's Universal Grammar, Natural Law, Coleridge's 'willing suspension of disbelief,' Jack Kerouac's vision of a global felahim, degeneration in immunology, or homeostasis. Students select, define, explore, and apply the heuristic beyond its native discipline.","tags":["heuristics","interdisciplinary","Freud","Chomsky","Heisenberg","critical thinking","cross-discipline"]},
  {"code":"IN516","title":"Wizard of Oz in American History","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T2"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"credits":"1IN/1EN","description":"Explores different versions of Oz and primary/secondary sources from important moments in American history. Connects Oz to the Gold Standard critique, WWII escapism, Civil Rights Movement, Black Lives Matter, and concerns about authoritarian rule and environmental protections. Asks: How and why does each version of Oz emerge from its time and place?","tags":["Wizard of Oz","American history","adaptation","Gold Standard","Civil Rights","cultural studies"]},
  {"code":"IN565","title":"Playwriting","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T1"],"forms":["V"],"year_long":False,"prerequisites":["400-level EN","300-level PA"],"ncaa_grants":["ENG"],"credits":"1IN/1EN","description":"Explores the art and craft of dramatic playwriting with focus on process and literature. Students synthesize dramatic structure through play readings and original works. Reads Suzan-Lori Parks, David Henry Hwang, Caryl Churchill. By term's end students will have written a stand-alone monologue, one 10-minute play, and one one-act play 30-40 minutes in length. Final staged reading before a live audience.","tags":["playwriting","drama","Suzan-Lori Parks","David Henry Hwang","one-act","staged reading","Caryl Churchill"]},
  {"code":"IN567","title":"Shakespeare's Tragedies: Everyone Dies in Performance","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T1"],"forms":["IV","V"],"year_long":False,"prerequisites":["300-level art class"],"ncaa_grants":[],"credits":"1IN/1EN","description":"Looks closely at the dramatic structure of three Shakespearian tragedies through the dual lens of theatrical performance and dramaturgical analysis. Students write analytical essays while learning performative techniques, ensemble work, fight choreography, and staging of conflict for the stage.","tags":["Shakespeare","tragedy","performance","fight choreography","dramaturgy","ensemble"]},
  {"code":"IN574","title":"Language of Leadership","department":"English","level":500,"honors":True,"interdisciplinary":True,"terms":["T3"],"forms":["V"],"year_long":False,"prerequisites":[],"ncaa_grants":[],"credits":"1IN/1EN","description":"Students gain an understanding of the 'history' of leadership through literature, informational texts, Harvard Business Review articles, and current research. Students develop their own 'definition' of leadership. Introduction to theories of adult development, learning, and ethics. Assessed via case study analyses, an essay of definition, and a project of the student's choice.","tags":["leadership","ethics","Harvard Business Review","adult development","definition","case study"]},
]